#include <iostream>
using namespace std;
long long n,c[100005],m,p1,s1,s2,p;
long long sum1=0,sum2=0,a,mn,ans1,ans2;
int main()
{
    cin>>n;
    for(int i=1;i<=n;i++)
    {
        cin>>c[i];
    }
    cin>>m>>p1>>s1>>s2;
    c[p1]+=s1;
    for(int i=1;i<=m-1;i++)
    {
        sum1=sum1+c[i]*(m-i);
    }
    for(int i=m;i<=n;i++)
    {
        sum2=sum2+c[i]*(i-m);
    }
    mn=abs(sum1-sum2);
    p=m;
    for(int i=1;i<=n;i++)
    {
        ans1=sum1;
        ans2=sum2;
        if(i<m)
        {
            ans1+=(m-i)*s2;
        }
        else if(i>m)
        {
            ans2+=(i-m)*s2;
        }
        if(abs(ans1-ans2)<mn)
        {
            mn=abs(ans1-ans2);
            p=i;
        }
    }
    cout<<p;
    return 0;
}
